arguments.content:
Add-Type -AssemblyName UIAutomationClient
Add-Type -AssemblyName UIAutomationTypes

# ค้นหาหน้าต่าง Chrome
$condition = New-Object System.Windows.Automation.PropertyCondition([System.Windows.Automation.AutomationElement]::NameProperty, "Owenzzz_bot - ChatGPT")
$chrome = [System.Windows.Automation.AutomationElement]::RootElement.FindFirst([System.Windows.Automation.TreeScope]::Children, $condition)

if ($null -eq $chrome) {
    # ลองหาแบบชื่อย่อย
    $condition = New-Object System.Windows.Automation.PropertyCondition([System.Windows.Automation.AutomationElement]::ClassNameProperty, "Chrome_WidgetWin_1")
    $chrome = [System.Windows.Automation.AutomationElement]::RootElement.FindFirst([System.Windows.Automation.TreeScope]::Children, $condition)
}

if ($chrome) {
    # ดึง Text ทั้งหมดจาก Element
    $text = $chrome.GetCurrentPropertyValue([System.Windows.Automation.AutomationElement]::NameProperty)
    # เจาะจงหาตัวแปรที่มีข้อมูลแชท
    $walker = [System.Windows.Automation.TreeWalker]::ControlViewWalker
    $element = $walker.GetFirstChild($chrome)

    function Get-TextRecursive($el) {
        $found = ""
        $name = $el.GetCurrentPropertyValue([System.Windows.Automation.AutomationElement]::NameProperty)
        if ($name) { $found += $name + "`n" }

        $child = $walker.GetFirstChild($el)
        while ($child) {
            $found += Get-TextRecursive($child)
            $child = $walker.GetNextSibling($child)
        }
        return $found
    }

    $allText = Get-TextRecursive($chrome)
    $allText | Out-File -FilePath "chat_content.txt" -Encoding utf8
} else {
    "Chrome window not found" | Out-File -FilePath "chat_content.txt"
}
